import{_ as t,o as s,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"63A. Reasonable Adjustments For Employees With A Disability","description":"","frontmatter":{"title":"63A. Reasonable Adjustments For Employees With A Disability","eba":"Nurses and Midwives 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/63A-reasonable-adjustments-for-employees-with-a-disability.md","filePath":"ebas/nurses-midwives/leave/63A-reasonable-adjustments-for-employees-with-a-disability.md"}'),i={name:"ebas/nurses-midwives/leave/63A-reasonable-adjustments-for-employees-with-a-disability.md"};function n(r,e,l,p,d,m){return s(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_63a-reasonable-adjustments-for-employees-with-a-disability" tabindex="-1">63A. Reasonable Adjustments For Employees With A Disability <a class="header-anchor" href="#_63a-reasonable-adjustments-for-employees-with-a-disability" aria-label="Permalink to &quot;63A. Reasonable Adjustments For Employees With A Disability&quot;">​</a></h1><p><strong>63A.1</strong> Purpose</p><p>The purpose of this clause is to reflect the obligations of the EO Act with respect to reasonable adjustments for Employees with a disability. The obligations apply regardless of whether the disability is or has been the subject of a WorkCover claim.</p><p><strong>63A.2</strong> Definitions</p><p><strong>(a)</strong> Disability has the same meaning as section 4 of the EO Act and includes:</p><p><strong>(i)</strong> malfunction of a part of the body including a mental or psychological disease or disorder or condition or disorder that results in a person learning more slowly than those without the condition or disorder;</p><p><strong>(ii)</strong> total or partial loss of a bodily function;</p><p><strong>(iii)</strong> presence in the body of organisms that may cause disease; or</p><p><strong>(iv)</strong> total or partial loss of a part of the body,</p><p>and includes a disability which is temporary or ongoing and that may exist in the future (including because of a genetic predisposition to that disability) and, to avoid doubt, behaviour that is a symptom or manifestation of a disability.</p><p><strong>(b)</strong> Reasonable adjustments has the same meaning as section 20 of the EO Act and requires consideration of all relevant facts and circumstances including:</p><p><strong>(i)</strong> the Employee&#39;s circumstances, including the nature of the disability;</p><p><strong>(ii)</strong> the nature of the Employee&#39;s role;</p><p><strong>(iii)</strong> the nature of the adjustment required to accommodate the Employee&#39;s disability;</p><p><strong>(iv)</strong> the financial circumstances of the Employer;</p><p><strong>(v)</strong> the size and nature of the workplace and the Employer&#39;s business;</p><p><strong>(vi)</strong> the effect on the workplace and the Employer&#39;s business of making the adjustment including the financial impact, the number of persons who would benefit or be disadvantaged and the impact of efficiency and productivity;</p><p><strong>(vii)</strong> the consequences for the Employer in making the adjustment; and</p><p><strong>(viii)</strong> the consequences for the Employee in not making the adjustment.</p><p><strong>63A.3</strong> Reasonable Adjustments</p><p>Where an Employer knows, or reasonably ought to have known, that an Employee has a disability, the Employer:</p><p><strong>(a)</strong> is required to make reasonable adjustments to enable the Employee to perform the genuine and reasonable requirements of the employment, subject to subclause (b)below; and</p><p><strong>(b)</strong> is not required to make reasonable adjustments if the Employee could not or cannot adequately perform the genuine and reasonable requirements of the employment even after the adjustments are made.</p><p>Plain language terms: disability adjustment, workplace adjustments, accessibility.</p>',24)])])}const c=t(i,[["render",n]]);export{u as __pageData,c as default};
